import type { ShoppingSession } from '../../domain/entities/shopping-session.entity';
import type { TransactionContext } from './unit-of-work.interface';

// Re-export so repositories can import the tx handle alongside the port.
export type { TransactionContext } from './unit-of-work.interface';

/**
 * Persistence port for the ShoppingSession aggregate (README §2.2 Rule 2/3).
 * Returns domain entities only — never Prisma rows. Every write accepts an
 * optional `tx` so it can enlist in the checkout `$transaction`.
 */
export const SESSION_REPOSITORY = 'ISessionRepository';

export interface ISessionRepository {
  /** Read-through cache then DB (README §2.7 stateless services). */
  findById(id: string, tx?: TransactionContext): Promise<ShoppingSession | null>;

  /** Enforces "at most one ACTIVE session per user" (README §2.8 Workflow 4). */
  findActiveByUser(userId: string): Promise<ShoppingSession | null>;

  /** ACTIVE sessions older than `threshold` — drives the expiration cron (§2.3). */
  findActiveOlderThan(threshold: Date): Promise<ShoppingSession[]>;

  /** Persist; invalidates/updates the cache only AFTER the tx commits (§2.7). */
  save(session: ShoppingSession, tx?: TransactionContext): Promise<void>;
}
